// Collect results from ALL merged inputs
let allResults = [];

for (const item of items) {
  if (item.json.local_results) {
    allResults = allResults.concat(item.json.local_results);
  }
}

return allResults.map(d => {

  // Extract fields safely
  const name = (d.title || "").toString().trim();
  const address = (d.address || "").toString().trim();
  const rating = parseFloat(d.rating || 0);
  const reviews = d.reviews || 0;
  const category = (d.type || "").toLowerCase();
  const price = (d.price || "").toString();

  // ✅ FIXED PHONE LOGIC
  let phone = (d.phone_number || d.phone || "").replace(/\D/g, "");

  // Remove +91 if present → keep only 10 digits
  if (phone.length === 12 && phone.startsWith("91")) {
    phone = phone.slice(2);
  }

  // Keep only valid Indian numbers
  if (phone.length !== 10) {
    phone = "";
  }

  // 🔥 SCORING LOGIC
  let score = 0;

  if (rating >= 4.5) score += 2;
  if (reviews >= 100) score += 1;
  if (price.includes("₹₹₹")) score += 2;
  if (
    category.includes("cafe") ||
    category.includes("bar") ||
    category.includes("restaurant")
  ) score += 1;

  // Priority classification
  let priority = "low";
  if (score >= 5) priority = "high";
  else if (score >= 3) priority = "medium";

  return {
    json: {
      name,
      phone,               // ✅ clean 10-digit (no sheet error)
      address,
      category,
      rating,
      price,
      priority,
      status: "new",
      action: "call",
      last_contact: "",
      attempts: 0,
      response: "",
      notes: ""
    }
  };
});

return items.map(item => {
  return {
    json: {
      row_number: item.json.row_number,
      name: item.json.name,
      phone: item.json.phone,
      address: item.json.address,
      category: item.json.category,
      rating: item.json.rating,
      price: item.json.price,
      priority: item.json.priority,
      status: "contacting",
      attempts: (item.json.attempts || 0) + 1,
      action: "call"
    }
  };
});

return items.map(item => {
  return {
    json: {
      ...item.json, // keep everything
      status: "contacting",
      attempts: (item.json.attempts || 0) + 1
    }
  };
});
